485→    // ===== 线性插值重采样 =====
486→    private float[] resample(float[] input, int fromRate, int toRate) {
487→        double ratio = (double) fromRate / toRate;
488→        int outputLen = (int) (input.length / ratio);
489→        float[] output = new float[outputLen];
490→        for (int i = 0; i < outputLen; i++) {
491→            double srcIdx = i * ratio;
492→            int idx = (int) srcIdx;
493→            double frac = srcIdx - idx;
494→            if (idx + 1 < input.length) {
495→                output[i] = (float) (input[idx] * (1 - frac) + input[idx + 1] * frac);
496→            } else if (idx < input.length) {
497→                output[i] = input[idx];
498→            }
499→        }
500→        return output;
501→    }
