590→    // ===== 开始对比 =====
591→    private void startCompare() {
592→        if (audioPath.isEmpty() || docPath.isEmpty()) {
593→            tvStatus.setText("请先选择录音和文档");
594→            return;
595→        }
596→        btnCompare.setEnabled(false);
597→        progressBar.setVisibility(View.VISIBLE);
598→        tvStatus.setText("正在处理...");
599→
600→        new Thread(() -> {
601→            try {
602→                Python py = Python.getInstance();
603→                PyObject engine = py.getModule("engine");
604→                PyObject jsonMod = py.getModule("json");
605→
606→                String audioText;
607→                String timestampsJson = "[]";  // 时间戳JSON
608→
609→                if (selectedEngine == 0) {
610→                    // Sherpa离线识别
611→                    runOnUiThread(() -> tvStatus.setText("正在解码音频..."));
612→                    audioText = transcribeSherpa(audioPath);
613→                    // 生成近似时间戳（基于音频时长）
614→                    PyObject tsList = engine.callAttr("create_approx_timestamps",
615→                        audioText, (double) lastAudioDuration);
616→                    timestampsJson = jsonMod.callAttr("dumps", tsList,
617→                        new com.chaquo.python.Kwarg("ensure_ascii", false)).toString();
618→                } else {
619→                    // 其他引擎: 调用Python转录（返回文本+时间戳）
620→                    String engineId = ENGINE_IDS[selectedEngine];
621→                    runOnUiThread(() -> tvStatus.setText(
622→                        "正在识别（" + ENGINE_NAMES[selectedEngine] + "）..."));
623→
624→                    SharedPreferences prefs = getSharedPreferences(PREFS_NAME, MODE_PRIVATE);
625→                    String extraArg = "";
626→                    if ("funasr".equals(engineId)) {
627→                        extraArg = prefs.getString("funasr_server", "http://192.168.1.100:8765");
628→                    } else if ("groq_whisper".equals(engineId)) {
629→                        extraArg = prefs.getString("groq_key", GROQ_BUILTIN_KEY);
630→                    } else if ("openai_whisper".equals(engineId)) {
631→                        extraArg = prefs.getString("openai_key", "");
632→                    }
633→
634→                    // 使用新的 transcribe_with_ts 获取文本+时间戳
635→                    PyObject tsResult = engine.callAttr("transcribe_with_ts",
636→                        audioPath, engineId, extraArg);
637→                    audioText = tsResult.callAttr("get", "text").toString();
638→                    PyObject tsList = tsResult.callAttr("get", "timestamps");
639→                    if (tsList != null) {
640→                        timestampsJson = jsonMod.callAttr("dumps", tsList,
641→                            new com.chaquo.python.Kwarg("ensure_ascii", false)).toString();
642→                    }
643→                }
644→
645→                Log.i(TAG, "ASR结果: " + audioText);
646→                Log.i(TAG, "时间戳数量: " + timestampsJson.length());
647→
648→                if (audioText.isEmpty()) {
649→                    runOnUiThread(() -> {
650→                        tvStatus.setText("语音识别结果为空，请检查音频是否有语音内容");
651→                        progressBar.setVisibility(View.GONE);
652→                        btnCompare.setEnabled(true);
653→                    });
654→                    return;
655→                }
656→
657→                // 读取文档文本
658→                runOnUiThread(() -> tvStatus.setText("正在对比文本..."));
659→                PyObject paragraphs = engine.callAttr("parse_docx", docPath);
660→                StringBuilder docTextBuilder = new StringBuilder();
661→                for (PyObject p : paragraphs.asList()) {
662→                    if (docTextBuilder.length() > 0) docTextBuilder.append("\n");
663→                    docTextBuilder.append(p.toString());
664→                }
665→                lastDocText = docTextBuilder.toString();
666→
667→                // 解析时间戳JSON为Python列表
668→                PyObject audioTimestamps = jsonMod.callAttr("loads", timestampsJson);
669→
670→                // 使用带时间戳的结构化对比
671→                PyObject result = engine.callAttr("run_compare_with_timestamps",
672→                    audioText, lastDocText, audioTimestamps);
673→
674→                String summary = result.callAttr("get", "summary").toString();
675→                PyObject diffsObj = result.callAttr("get", "diffs");
676→
677→                // LLM智能审核：过滤转写误差（同音字等）
678→                SharedPreferences prefs = getSharedPreferences(PREFS_NAME, MODE_PRIVATE);
679→                String llmProvider = prefs.getString("llm_provider", "");
680→                String llmKey = prefs.getString("llm_key", "");
681→                if (!llmProvider.isEmpty() && !llmKey.isEmpty()) {
682→                    runOnUiThread(() -> tvStatus.setText("大模型审核差异中..."));
683→                    try {
684→                        diffsObj = engine.callAttr("llm_review_diffs",
685→                            diffsObj, lastDocText, audioText, llmProvider, llmKey);
686→                        // 更新摘要
687→                        int totalDiffs = diffsObj.asList().size();
688→                        int nMis = 0, nMiss = 0, nExt = 0;
689→                        for (PyObject d : diffsObj.asList()) {
690→                            String t = d.callAttr("get", "type", "").toString();
691→                            if ("mismatch".equals(t)) nMis++;
692→                            else if ("missing".equals(t)) nMiss++;
693→                            else nExt++;
694→                        }
695→                        summary = String.format("共%d处差异：%d处误读，%d处漏读，%d处多读\n(已经大模型审核过滤)",
696→                            totalDiffs, nMis, nMiss, nExt);
697→                    } catch (Exception e) {
698→                        Log.w(TAG, "LLM审核失败，使用原始结果: " + e.getMessage());
699→                    }
700→                }
701→
702→                // 保存结构化差异JSON（含时间戳）
703→                lastDiffsJson = jsonMod.callAttr("dumps", diffsObj,
704→                    new com.chaquo.python.Kwarg("ensure_ascii", false)).toString();
705→
706→                // 格式化显示
707→                StringBuilder details = new StringBuilder();
708→                int idx = 1;
709→                for (PyObject d : diffsObj.asList()) {
710→                    String dtype = d.callAttr("get", "type", "").toString();
711→                    String docT = d.callAttr("get", "docText", "").toString();
712→                    String audioT = d.callAttr("get", "audioText", "").toString();
713→                    if ("mismatch".equals(dtype)) {
714→                        details.append(idx).append(". [误读] 原文: ")
715→                            .append(docT).append(" → 录音: ").append(audioT);
716→                    } else if ("missing".equals(dtype)) {
717→                        details.append(idx).append(". [漏读] ").append(docT);
718→                    } else {
719→                        details.append(idx).append(". [多读] ").append(audioT);
720→                    }
721→                    // 显示时间戳（精确到秒）
722→                    PyObject tsObj = d.callAttr("get", "time_start");
723→                    if (tsObj != null && !"None".equals(tsObj.toString())) {
724→                        try {
725→                            double ts = tsObj.toDouble();
726→                            int m = (int) ts / 60;
727→                            int s = (int) ts % 60;
728→                            details.append("  ⏰ ").append(m).append("分").append(s).append("秒");
729→                        } catch (Exception ignore) {}
730→                    }
731→                    details.append("\n");
732→                    idx++;
733→                }
734→
735→                String finalDetails = details.toString();
736→                String finalSummary = summary;
737→
738→                // 保存结果
739→                lastAudioText = audioText;
740→                lastReportPath = "";
741→
742→                runOnUiThread(() -> {
743→                    tvStatus.setText("对比完成");
744→                    tvResult.setText(finalSummary + "\n\n" + finalDetails);
745→                    scrollResult.setVisibility(View.VISIBLE);
746→                    progressBar.setVisibility(View.GONE);
747→                    btnCompare.setEnabled(true);
748→                    if (btnGenerateReport != null) btnGenerateReport.setVisibility(View.VISIBLE);
749→                    if (btnShare != null) btnShare.setVisibility(View.VISIBLE);
750→                });
751→            } catch (Exception e) {
752→                Log.e(TAG, "处理失败", e);
753→                String errMsg = e.getMessage();
754→                if (errMsg == null) errMsg = e.getClass().getSimpleName();
755→                String finalErr = errMsg;
756→                runOnUiThread(() -> {
757→                    tvStatus.setText("错误: " + finalErr);
758→                    progressBar.setVisibility(View.GONE);
759→                    btnCompare.setEnabled(true);
760→                });
761→            }
762→        }).start();
763→    }
